}

function readTextPaste(event: PasteEvent): string | null {
	if (
		event.metadata?.kind === "binary" ||
		event.metadata?.mimeType?.startsWith("image/")
	) {
		return null;
	}

	return stripAnsiSequences(decodePasteBytes(event.bytes));
}

